// Update all UI elements with fixture data
const inputs = msg.payload.inputs;
const ts = msg.payload.timestamp;

return [
    { payload: inputs.p1_power || 0 },
    { payload: inputs.pv_power || 0 },
    { payload: inputs.temp_living || 20 },
    { payload: inputs.temp_bedroom || 20 },
    { payload: inputs.ev_state || 128 },
    { payload: inputs.pool_season === 'on' },
    { payload: ts }
];

// This function simulates the decision engine
// In production, this would import from ../src/logic/

const { timestamp, inputs } = msg.payload;
const now = new Date(timestamp);

// Simplified tariff detection
const hour = now.getHours();
const day = now.getDay();
const isWeekend = day === 0 || day === 6;

let tariff = 'off-peak';
let max = 5000;

if (!isWeekend) {
    if (hour >= 7 && hour < 11) {
        tariff = 'peak';
        max = 2500;
    } else if (hour >= 17 && hour < 22) {
        tariff = 'peak';
        max = 2500;
    } else if (hour >= 22 || hour < 7) {
        tariff = 'super-off-peak';
        max = 8000;
    }
} else {
    if (hour >= 22 || hour < 7 || (hour >= 13 && hour < 17)) {
        tariff = 'super-off-peak';
        max = 8000;
    }
}

// Calculate available headroom
const p1 = typeof inputs.p1_power === 'number' ? inputs.p1_power * 1000 : 0;
const available = max - p1;

// Build decisions
const decisions = {
    ev: { action: 'none', amps: 0 },
    boiler: { action: 'none' },
    pool: { action: 'none' },
    acLiving: { action: 'none' },
    acBedroom: { action: 'none' },
    acOffice: { action: 'none' },
    acMancave: { action: 'none' },
    heaterTable: { action: 'none' },
    heaterRight: { action: 'none' }
};

const plan = [];
const isSummer = inputs.pool_season === 'on';
const isExporting = p1 < 0;

// Status line
const tariffName = tariff.toUpperCase().replace('-', ' ');
plan.push(`${tariffName} | ${(p1/1000).toFixed(1)}kW | ${(available/1000).toFixed(1)}kW avail`);

// EV logic
const evState = inputs.ev_state;
if (evState === 128) {
    plan.push('EV: No car');
} else if (evState === 130) {
    plan.push('EV: Full');
} else if (evState === 129 || evState === 132) {
    if (tariff !== 'peak' && available > 1400) {
        decisions.ev.action = 'on';
        decisions.ev.amps = Math.min(16, Math.max(6, Math.floor(available / 230)));
        plan.push(`EV: Starting ${decisions.ev.amps}A`);
    } else if (tariff === 'peak') {
        plan.push('EV: Waiting for off-peak');
    } else {
        plan.push('EV: Insufficient headroom');
    }
}

// Boiler logic
const boilerFull = inputs.boiler_power < 50;
if (!boilerFull && tariff === 'super-off-peak') {
    decisions.boiler.action = 'on';
    plan.push('Boiler: Heating (super off-peak)');
} else if (boilerFull) {
    plan.push('Boiler: Full');
}

// Pool logic (summer only)
if (isSummer) {
    plan.push('Season: Summer');
    if (isExporting) {
        decisions.pool.action = 'heat';
        plan.push('Pool: Heating (exp)');
    }

    // AC cooling when exporting
    if (isExporting && inputs.temp_living > 25) {
        decisions.acLiving.action = 'cool';
        plan.push('AC Living: Cooling');
    }
} else {
    plan.push('Season: Winter');
}

// Apply overrides
if (inputs.ovr_ac_living === 'Cool') {
    decisions.acLiving.action = 'cool';
    plan.push('AC Living: MANUAL COOL');
} else if (inputs.ovr_ac_living === 'Heat') {
    decisions.acLiving.action = 'heat';
    plan.push('AC Living: MANUAL HEAT');
} else if (inputs.ovr_ac_living === 'Off') {
    decisions.acLiving.action = 'off';
    plan.push('AC Living: MANUAL OFF');
}

if (inputs.ovr_ev === 'Off' && decisions.ev.action !== 'none') {
    decisions.ev.action = 'off';
    plan.push('EV: MANUAL OFF');
} else if (inputs.ovr_ev === 'On' && inputs.ev_state === 129) {
    decisions.ev.action = 'on';
    decisions.ev.amps = 16;
    plan.push('EV: MANUAL ON');
}

msg.payload = {
    timestamp: timestamp,
    meta: {
        tariff: tariff,
        max: max,
        p1: p1,
        pv: inputs.pv_power || 0,
        isSummer: isSummer,
        isExporting: isExporting
    },
    headroom: available,
    decisions: decisions,
    plan: plan
};

return msg;

const result = msg.payload;

// Format plan for display
const planText = result.plan.join('\n');

// Format decisions
let decisionsText = '';
for (const [device, decision] of Object.entries(result.decisions)) {
    if (decision.action !== 'none') {
        let line = `${device}: ${decision.action}`;
        if (decision.amps) line += ` (${decision.amps}A)`;
        decisionsText += line + '\n';
    }
}
if (!decisionsText) decisionsText = 'No actions required';

// Format meta
const meta = result.meta;
const metaText = `Tariff: ${meta.tariff}\nMax: ${meta.max}W\nP1: ${meta.p1}W\nHeadroom: ${result.headroom}W\nSeason: ${meta.isSummer ? 'Summer' : 'Winter'}\nExporting: ${meta.isExporting ? 'Yes' : 'No'}`;

return [
    { payload: planText },
    { payload: decisionsText },
    { payload: metaText },
    { payload: JSON.stringify(result, null, 2) }
];
